const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { createHash } = require('crypto');

const sqsClient = new SQSClient({ region: process.env.AWS_REGION || 'us-east-1' });
const queueUrl = process.env.QUEUE_URL;

const processedMessages = new Map();
const MESSAGE_RETENTION_TIME = 3600000; // 1 hour

function cleanupOldMessages() {
  const now = Date.now();
  for (const [messageId, timestamp] of processedMessages.entries()) {
    if (now - timestamp > MESSAGE_RETENTION_TIME) {
      processedMessages.delete(messageId);
    }
  }
}

setInterval(cleanupOldMessages, 300000); // Clean up every 5 minutes

function generateMessageHash(messageBody) {
  return createHash('sha256').update(messageBody).digest('hex');
}

function isMessageProcessed(messageId, messageHash) {
  const key = `${messageId}-${messageHash}`;
  return processedMessages.has(key);
}

function markMessageAsProcessed(messageId, messageHash) {
  const key = `${messageId}-${messageHash}`;
  processedMessages.set(key, Date.now());
}

function validateTransactionMessage(message) {
  if (!message || typeof message !== 'object') {
    throw new Error('Invalid message format');
  }

  const requiredFields = ['transactionId', 'amount', 'currency', 'accountId', 'type'];
  for (const field of requiredFields) {
    if (!(field in message)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  if (typeof message.amount !== 'number' || message.amount <= 0) {
    throw new Error('Invalid amount');
  }

  if (!['USD', 'EUR', 'GBP'].includes(message.currency)) {
    throw new Error('Invalid currency');
  }

  if (!['debit', 'credit'].includes(message.type)) {
    throw new Error('Invalid transaction type');
  }

  if (typeof message.accountId !== 'string' || !/^[A-Z0-9]{10,20}$/.test(message.accountId)) {
    throw new Error('Invalid account ID format');
  }

  if (typeof message.transactionId !== 'string' || !/^[A-Z0-9-]{10,50}$/.test(message.transactionId)) {
    throw new Error('Invalid transaction ID format');
  }

  return true;
}

