async function receiveAndProcessMessages() {
  try {
    const receiveParams = {
      QueueUrl: queueUrl,
      MaxNumberOfMessages: 10,
      WaitTimeSeconds: 20,
      VisibilityTimeout: 60,
      AttributeNames: ['All'],
      MessageAttributeNames: ['All']
    };

    const { Messages } = await sqsClient.send(new ReceiveMessageCommand(receiveParams));

    if (!Messages || Messages.length === 0) {
      console.log('No messages to process');
      return;
    }

    for (const message of Messages) {
      try {
        const messageHash = generateMessageHash(message.Body);
        
        if (isMessageProcessed(message.MessageId, messageHash)) {
          console.log(`Duplicate message detected: ${message.MessageId}, skipping processing`);
          await sqsClient.send(new DeleteMessageCommand({
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle
          }));
          continue;
        }

        const transaction = JSON.parse(message.Body);
        
        validateTransactionMessage(transaction);
        
        await processTransaction(transaction);
        
        markMessageAsProcessed(message.MessageId, messageHash);
        
        await sqsClient.send(new DeleteMessageCommand({
          QueueUrl: queueUrl,
          ReceiptHandle: message.ReceiptHandle
        }));
        
        console.log(`Message ${message.MessageId} deleted from queue`);
        
      } catch (error) {
        console.error(`Error processing message ${message.MessageId}:`, error);
        
        const receiveCount = parseInt(message.Attributes?.ApproximateReceiveCount || '0');
        if (receiveCount >= 3) {
          console.error(`Message ${message.MessageId} exceeded retry limit, moving to DLQ`);
          await sqsClient.send(new DeleteMessageCommand({
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle
          }));
        }
      }
    }
  } catch (error) {
    console.error('Error receiving messages from SQS:', error);
  }
}

async function startConsumer() {
  console.log('Starting SQS consumer for financial transactions...');
  
  while (true) {
    await receiveAndProcessMessages();
    await new Promise(resolve => setTimeout(resolve, 1000));
  }
}

